#include <iostream>
#include <vector>

void drawPattern(int depth, int startVal) {
    if (depth == 0) return;
    for (int i = 0; i < depth; ++i) {
        std::cout << startVal + i << " ";
    }
    std::cout << "\n";
    drawPattern(depth - 1, startVal + depth);
}

int main() {
    std::cout << "Starting sequence...\n";
    drawPattern(5, 10);
    return 0;
}
```

